
import React from 'react'
import { Breadcrumb } from 'react-bootstrap'
import { NavLink } from 'react-router-dom'

const BreadCrumb = (props) => {
  return (
    <Breadcrumb className='ms-2'>
      {
        props.matches.map((match, index) => {
          const { path, breadcrumbName } = match.route
          const isActive = match.pathname === location.pathname

          return isActive ? (
            <Breadcrumb.Item className='fw-bold font-content fs-5'
              key={index} active>
              {breadcrumbName === 'Detail' ? props.productName : breadcrumbName}
            </Breadcrumb.Item>
          ) : (
            <Breadcrumb.Item className='fw-bold font-content  fs-5'
              key={index}>
              <NavLink to={path}>
                {breadcrumbName}
              </NavLink>
            </Breadcrumb.Item>
          )
        })
      }
    </Breadcrumb>
  )
}
export default BreadCrumb
