
import React, { useRef, memo } from 'react'
import { Col, Card } from 'react-bootstrap'
import { Link } from 'react-router-dom'
import { LazyLoadImage } from "react-lazy-load-image-component";
const ProductCard = (
  {
    productItem: {
      _id,
      product_category,
      product_name,
      product_price,
      product_images,
      product_discount,
    }
  }) => {

  return (

    <Col className="py-2 d-flex" >
      <Card border="secondary" style={{ minHeight: "383px" }} className="border border-1 p-1 border-gray">
        <Link to={`/products/${product_category}/${_id}`}>
          <LazyLoadImage
            style={{ minHeight: "246px", minWidth: "100%" }}
            src={product_images && product_images[0]}
            className="bg-lavender w-100 h-100"
          />
        </Link>
        <Card.Body className='d-flex w-100 h-100 justify-content-between flex-column'>
          <Card.Title as="p" className='fs-5 font-content fw-bold text-gray align-self-center'>{product_name}</Card.Title>
          {
            product_discount < 1 ? (
              <div className='d-flex justify-content-end'>
                <Card.Text className='mx-1 mb-0 fs-6 font-content text-decoration-line-through'>
                  {product_price}NT$
                </Card.Text>
                <Card.Text className='fs-5 text-red font-content'>
                  {Math.floor(product_price * product_discount)}NT$
                </Card.Text>
              </div>
            ) : (
              <Card.Text className='fs-5 font-content d-flex justify-content-end'>{product_price}NT$</Card.Text>
            )
          }
        </Card.Body>
      </Card>
    </Col >
  )
}

export default memo(ProductCard)
