import React, { useState, useEffect, useRef } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Nav, Navbar, NavDropdown, FormControl, Button, Container, Stack } from 'react-bootstrap';
import { NavLink, useMatch, useNavigate } from 'react-router-dom';
import { CartIcon, SearchIcon } from '../../../src/Icons';
import Person from '../../../src/components/Person';
import { userTypes } from '../../redux/userModule';

const NavArea = (props) => {
  const dispatch = useDispatch();
  const searchRef = useRef();
  const navigate = useNavigate()
  const pathName = location.pathname
  const [isToggle, setIsToggle] = useState(false);
  const matched = useMatch('manage/*');
  const { info: { user_name, user_role }, error, isLogin } = useSelector((state) => state.user);
  const loginToken = localStorage.getItem('loginToken')
  useEffect(() => {
    if (loginToken) dispatch({ type: userTypes.CHECK_USER_AUTH_REQUEST });
  }, []);

  useEffect(() => {
    if (matched && !isLogin && !loginToken) {
      navigate('/');
    } else if (matched && (user_role && user_role !== 'admin')) {
      navigate('/');
    }
  }, [isLogin, loginToken]);

  const handleToggle = () => {
    if (isToggle) {
      setIsToggle(toggle => !toggle);
    }
  };

  const handleLogout = () => {
    dispatch({ type: userTypes.LOGOUT_REQUEST });
  };

  const checkLogin = (e) => {
    if (!isLogin) {
      alert("Please login your account.");
      e.preventDefault();
    }
  };

  const handleKeyDown = (e) => {
    if (e.keyCode == 13) {
      navigate(`search?q=${e.target.value}`);
      e.preventDefault();
    }
  };

  return (
    <>
      <Navbar
        collapseOnSelect
        expanded={isToggle}
        className="px-3 index-2 bg-light-gray border d-flex  justify-content-between position-fixed top-0 start-0 end-0"
        expand="lg"
      >
        <NavLink as={NavLink} to="/" className="me-1 fs-1 text-light font-title nav-animation">
          WaveSight
        </NavLink>
        <Navbar.Collapse id="navbarScroll" className="justify-content-around">
          <Nav className='mb-2 d-flex  align-items-baseline'>
            {!matched ?
              props.navLink?.map((link, index) =>
                <Nav.Item key={index}>
                  <Nav.Link
                    className='py-0 p-1 mb-1 fs-4 fw-bold  border-2 border-end  text-decoration font-nav'
                    as={NavLink}
                    to={link.path}>
                    {link.linkName}
                  </Nav.Link>
                </Nav.Item>)
              : <>{props.manageNavLink?.map((link, index) =>
                <Nav.Item key={index}>
                  <Nav.Link
                    className='py-0 fs-4 fw-bold border-2 border-end  text-decoration font-nav'
                    as={NavLink}
                    to={link.path}>
                    {link.linkName}
                  </Nav.Link>
                </Nav.Item>)}
                <NavDropdown
                  title="Manage"
                  id="nav-dropdown"
                  menuVariant='dark'
                  className='py-0 fs-4 fw-bold border-2 border-end ms-1 text-decoration font-nav'>{
                    props.manageGroupLink?.map((link, index) =>
                      <NavDropdown.Item
                        eventKey={index}
                        className='bg-light-gray border border-1'>
                        <Nav.Link
                          className='fs-4 fw-bold  text-decoration font-nav'
                          as={NavLink}
                          to={link.path}>
                          {link.linkName}
                        </Nav.Link>
                      </NavDropdown.Item>
                    )}
                </NavDropdown>
              </>}
            {!matched &&
              <div className='d-flex ms-2'>
                <FormControl
                  type="search"
                  placeholder="Search"
                  ref={searchRef}
                  className=""
                  aria-label="Search"
                  onKeyDown={(e) => handleKeyDown(e)}
                />
                <Button
                  variant="none"
                  className="ms-1 border border-white"
                  onClick={() => navigate(`search?q=${searchRef.current.value}`)}
                >
                  <SearchIcon />
                </Button></div>
            }
          </Nav>
        </Navbar.Collapse>
        <div className='ms-3 d-flex'>
          <Stack
            direction="horizontal"
            gap={2}
          >
            {!matched ?
              <NavLink
                to="user/cart"
                className='text-black border border-2 p-1'
                onClick={e => checkLogin(e)}
              >
                <CartIcon
                  viewBox="0 0 18 18"
                  width="33"
                  height="33"
                />
              </NavLink> : null
            }
            <Person
              userInfo={{ user_name, user_role }}
              handleLogout={handleLogout}
              isLogin={isLogin}
            />
          </Stack>
          <Navbar.Toggle
            onClick={() => setIsToggle(toggle => !toggle)}
            aria-controls="navbarScroll"
            className='ms-2 border border-white'
          />
        </div>
      </Navbar >
      <div
        className="index-1  position-fixed bottom-0 top-0 end-0 start-0"
        onClick={() => handleToggle()}
        style={{ display: `${isToggle ? "block" : "none"} ` }}
      />
    </>
  )
}

export default NavArea
