import React, { useRef } from 'react'
import { Form } from 'react-bootstrap'

const Filter = ({ handlePriceSort }) => {

  const priceRef = useRef()
  return (
    < Form >
      <Form.Group>
        <Form.Label className="fw-bold fs-5 text-center font-content"
          column sm={12}>Price</Form.Label>
        <Form.Label />
        <Form.Select ref={priceRef} onChange={() => handlePriceSort(priceRef.current.value)}>
          <option className="fs-6 font-content">Default</option>
          <option className="fs-6 font-content" value="High">High</option>
          <option className="fs-6 font-content" value="Low">Low</option>
        </Form.Select>
      </Form.Group>
    </Form >
  )
}
export default Filter
