import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { Table, Container } from "react-bootstrap";
import Create from "../Create";
import ProductTable from "../../../components/ProductTable";
import { manageTypes } from "../../../redux/manageModule";
import { useEditInterface } from "../../../hooks/useEditInterface";
import PageList from "../../../components/PageList";

const EditProduct = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const { items, totalPages } = useSelector((state) => state.manage.products);
    const pageQuery = location.search;
    const currentIndex = (pageQuery.split('?page=')[1] - 1) || 0;
    const limit = 5;
    const startIndex = currentIndex * limit;
    const endIndex = startIndex + limit || limit;
    const pageItems = items[startIndex] ? items.slice(startIndex, endIndex) : [];

    const {
        isDisplay,
        value: productValue,
        setValue: setProductValue,
        openEditInterface,
        closeEditInterface
    } = useEditInterface();

    useEffect(() => {
        dispatch({ type: manageTypes.GET_ALL_PRODUCTS_REQUEST, payload: { pageQuery, limit } })
    }, [pageQuery])

    return (
        <Container className=" border border-1 my-2 py-2">
            <h1
                style={{ fontFamily: "fantasy" }}
                className="mt-2 border bg-gray text-white d-flex justify-content-center">
                Product Manage
            </h1>
            {isDisplay ? (
                <Create
                    isDisplay
                    productValue={productValue}
                    closeEditInterface={closeEditInterface}
                />
            ) : (<>
                <Table striped bordered hover>
                    <thead>
                        <tr className="text-center font-content">
                            <th>No.</th>
                            <th>Product Name</th>
                            <th>Image</th>
                            <th>Sale Status</th>
                            <th>New Sale</th>
                            <th>Popular</th>
                            <th>Discount</th>
                        </tr>
                    </thead>
                    <tbody >{pageItems?.map((item, index) =>
                        <ProductTable
                            key={item._id}
                            num={index + startIndex}
                            {...{ item }}
                            openEditInterface={openEditInterface}
                        />)}</tbody>
                </Table>
                <PageList currentIndex={currentIndex} totalPages={totalPages} />
            </>)}
        </Container >)
}
export default EditProduct