import { put, takeLatest, call, select } from 'redux-saga/effects';
import {
    createProduct,
    getAllProducts,
    updateProduct,
    updateUser,
    getAllUsers
} from '../../services/axiosApi'
import { manageTypes } from '../manageModule';
import { userTypes } from '../userModule';


function* watchCreateProduct(action) {
    try {
        const productValue = action.payload;
        const res = yield call(createProduct, productValue);
        const products = yield select((state) => state.manage.products);
        const newProducts = [...products];
        newProducts.push(res.data)
        yield put({ type: manageTypes.CREATE_PRODUCT_SUCCESS, payload: newProducts })
        alert('create success!')
    } catch (err) {
        const { data, status } = err.response

        if (status === 401) {
            localStorage.clear()
            alert(`${data} please login again.(${status})`)
            yield put({ type: userTypes.USER_ANY_FAILURE, payload: { info: {}, isLogin: false, error: { data, status } } })
        } {
            yield put({ type: manageTypes.MANAGE_FAILURE, payload: { error: { data, status } } })
            alert(`${data}`)
        }

    }
}

function* watchUpdateProduct(action) {
    try {
        const productValue = action.payload
        const res = yield call(updateProduct, productValue)
        const products = yield select(state => state.manage.products)
        const newState = [...products];
        const target = newState.findIndex((product) => product._id === res.data._id);
        newState[target] = res.data;
        yield put({ type: manageTypes.UPDATE_PRODUCT_SUCCESS, payload: newState })
        alert('Update success!')
    } catch (err) {
        const { data, status } = err.response

        if (status === 401) {
            localStorage.clear()
            alert(`${data} please login again.(${status})`)
            yield put({ type: userTypes.USER_ANY_FAILURE, payload: { info: {}, isLogin: false, error: { data, status } } })
        } else {
            alert('Update failed!')
            yield put({ type: manageTypes.MANAGE_ANY_FAILURE, payload: { error: { data, status } } })
        }
    }
}
function* watchUpdateUser(action) {
    try {
        const userInfo = action.payload

        const res = yield call(updateUser, userInfo)
        const resultData = res.data
        const { users } = yield select((state) => state.manage)
        const userIndex = users.findIndex((user) => user._id === resultData._id)
        const newResultData = [...users]
        if (userIndex !== -1) {
            newResultData[userIndex] = resultData
        }
        yield put({ type: manageTypes.UPDATE_USER_SUCCESS, payload: newResultData })
        alert(`${resultData.user_name} Update success.`)
    } catch (err) {
        const { data, status } = err.response
        if (status === 401) {
            localStorage.clear()
            alert(`${data} please login again.(${status})`)
            yield put({ type: userTypes.USER_ANY_FAILURE, payload: { info: {}, isLogin: false, error: { data, status } } })
        } else {
            alert('Update failed!')
            yield put({ type: manageTypes.MANAGE_ANY_FAILURE, payload: { error: { data, status } } })
        }

    }
}
function* watchGetAllProducts(action) {
    const { pageQuery, limit } = action.payload;
    const currentPage = pageQuery === undefined ? 0 : (pageQuery.split('?page=')[1]) - 1;
    const startIndex = currentPage * limit;
    try {
        const { items, totalPages } = yield select((state) => state.manage.products);
        const newProducts = items ? [...items] : Array.from({ length: currentPage }, () => null)
        if (!newProducts[startIndex]) {
            const res = yield call(getAllProducts, pageQuery);
            const result = res.data.result;
            const pageGap = Array.from({ length: startIndex - newProducts.length }, () => null)
            newProducts.splice(startIndex, limit, ...pageGap, ...result)
            yield put({ type: manageTypes.GET_ALL_PRODUCTS_SUCCESS, payload: { items: newProducts, totalPages: Number(res.data.totalPages) } });
        }

    } catch (err) {
        const { data, status } = err.response
        yield put({ type: manageTypes.MANAGE_ANY_FAILURE, payload: { error: { data, status } } })
    }
}

function* watchGetAllUsers() {
    try {
        const res = yield call(getAllUsers)
        yield put({ type: manageTypes.GET_ALL_USERS_SUCCESS, payload: res.data })
    } catch (err) {
        const { data, status } = err.response
        yield put({ type: manageTypes.MANAGE_ANY_FAILURE, payload: { error: { data, status } } })
    }
}

export default function* manageSaga() {
    yield takeLatest(manageTypes.CREATE_PRODUCT_REQUEST, watchCreateProduct)
    yield takeLatest(manageTypes.UPDATE_PRODUCT_REQUEST, watchUpdateProduct)
    yield takeLatest(manageTypes.UPDATE_USER_REQUEST, watchUpdateUser)
    yield takeLatest(manageTypes.GET_ALL_PRODUCTS_REQUEST, watchGetAllProducts)
    yield takeLatest(manageTypes.GET_ALL_USERS_REQUEST, watchGetAllUsers)
}

