import React from 'react'
import useInputValidate from '../../hooks/useInputValidate'
import { Button, Form, FormGroup, FormControl, FormLabel, Modal } from 'react-bootstrap'
import { PASSWORD_REGEX, EMAIL_REGEX } from '../../utils/constants/formValid'

const isPasswordFormat = (value) => PASSWORD_REGEX.test(value);
const isEmailFormat = (value) => EMAIL_REGEX.test(value);

const LoginModal = ({ handleDisplay, onClick, isDisplay }) => {

  const {
    value: user_email,
    message: messageEmail,
    isValid: emailIsValid,
    isConfirm: emailIsConfirm,
    onChangeValue: onChangeEmail,
    onBlurValue: onBlurEmail,
  } = useInputValidate(isEmailFormat, 'email');

  const {
    value: user_password,
    message: messagePassword,
    isValid: passwordIsValid,
    isConfirm: passwordIsConfirm,
    onChangeValue: onChangePassword,
    onBlurValue: onBlurPassword,
  } = useInputValidate(isPasswordFormat, 'password');

  return (
    <Modal
      show={isDisplay}
      onHide={handleDisplay}
      size="md"
      aria-labelledby="contained-modal-title-vcenter"
      contentClassName="bg-light-gray"
      centered
    >
      <Modal.Header closeButton>
        <Modal.Title className="fs-2 font-title" id="contained-modal-title-vcenter">
          Login
        </Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <Form >
          <FormGroup className="mb-3" controlId="formBasicEmail">
            <FormLabel className='fs-5 font-content'>Email address</FormLabel>
            <FormControl
              type="email"
              placeholder="Enter email"
              value={user_email}
              onChange={onChangeEmail}
              onBlur={onBlurEmail}
            />
            <Form.Text className="text-danger" hidden={emailIsValid}>
              {messageEmail}
            </Form.Text>
          </FormGroup>
          <FormGroup className="mb-3" controlId="formBasicPassword">
            <FormLabel className='fs-5 font-content'>Password</FormLabel>
            <FormControl
              type="password"
              placeholder="Password"
              value={user_password}
              onChange={onChangePassword}
              onBlur={onBlurPassword}
            />
            <Form.Text className="text-danger" hidden={passwordIsValid}>
              {messagePassword}
            </Form.Text>
          </FormGroup>
        </Form>
      </Modal.Body>
      <Modal.Footer>
        <Button
          disabled={!emailIsConfirm || !passwordIsConfirm}
          variant="fs-4 outline-light bg-deep-gray text-white font-btn"
          onClick={onClick({ user_email, user_password })}
        >
          Login
        </Button>
      </Modal.Footer>
    </Modal >
  )
}
export default LoginModal
