import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { Button } from 'react-bootstrap'

const withModal = (ModalComponent) => {

    return (props) => {
        const dispatch = useDispatch();
        const [isDisplay, setIsDisplay] = useState(false);
        const handleDisplay = (bool) => { return () => setIsDisplay(bool); }

        const onClick = (userInfo) => {
            return () => {
                const { user_role } = props.userInfo || ""
                if (user_role !== 'admin' && props.name === 'Change Password') {
                    alert('No permission.');
                    return;
                }
                dispatch({ type: props.actionType, payload: userInfo });
            }
        }

        return (
            <>
                <ModalComponent
                    {...props}
                    isDisplay={isDisplay}
                    handleDisplay={handleDisplay(false)}
                    onClick={onClick}
                />
                <Button
                    className={`index-2 fs-${props.btnSize || 6} text-white outline-light
                    btn-deep-gray border ms-2 font-btn`}
                    onClick={handleDisplay(true)}>
                    {props.name}
                </Button>
            </>
        );
    };
};

export default withModal;