import React from "react";
import { Button } from "react-bootstrap";

const UserTable = ({
    item,
    openEditInterface,
    num
}) => {
    const { user_name,
        user_email,
        user_address,
        user_role,
        user_status,
        create_time } = item
    return (
        <>
            <tr className="text-center font-content border border-1">
                <td>{num + 1}</td>
                <td>{user_name}</td>
                <td>{user_email}</td>
                <td>{user_address}</td>
                <td>{user_role}</td>
                <td>{Number(user_status)}</td>
                <td>{create_time}</td>
                <Button
                    type="button"
                    size="sm"
                    className='m-1 btn-gray border  border-1 '
                    onClick={() => openEditInterface(item)}
                >
                    Modify
                </Button>
            </tr>
        </>
    )
}
export default UserTable