import React from "react";
import { useEffect, useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { manageTypes } from "../../../redux/manageModule";
import { Table } from "react-bootstrap";
import UserTable from "../../../components/UserTable";
import UserForm from "../../../components/UserForm"
import { useEditInterface } from "../../../hooks/useEditInterface";

const EditUser = () => {
    const dispatch = useDispatch()
    const users = useSelector((state) => state.manage.users)
    const {
        isDisplay,
        value: userValue,
        setValue: setUserValue,
        openEditInterface,
        closeEditInterface
    } = useEditInterface();

    useEffect(() => {
        if (!users) return
        dispatch({ type: manageTypes.GET_ALL_USERS_REQUEST })
    }, [])

    const updateUser = (userInfo) => {
        dispatch({ type: manageTypes.UPDATE_USER_REQUEST, payload: userInfo })
        closeEditInterface()
    }
    const userItems =
        users?.map((item, index) => (
            <UserTable key={item._id}
                num={index}
                {...{ item }}
                openEditInterface={openEditInterface}
            />))
    return (
        <div className=" border border-1 p-2 my-2">
            <h1 style={{ fontFamily: "fantasy" }} className="mt-2 bg-gray border  text-white text-center">
                User Manage
            </h1>
            {isDisplay ? (
                <UserForm
                    userValue={userValue}
                    setUserValue={setUserValue}
                    updateUser={updateUser}
                    closeEditInterface={closeEditInterface}
                />) : (
                <Table striped bordered >
                    <tbody >
                        <tr className=" text-center font-content">
                            <th>No.</th>
                            <th>Name</th>
                            <th>Email</th>
                            <th>Address</th>
                            <th>Role</th>
                            <th>Status</th>
                            <th>Create Time</th>
                            <th>Edit</th>
                        </tr>
                        {userItems}
                    </tbody>
                </Table>)
            }
        </div >
    )
}
export default EditUser