import React, { useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { Outlet, matchRoutes, useMatch } from 'react-router-dom'
import { Row, Col, Container } from 'react-bootstrap'
import BreadCrumb from '../../../components/BreadCrumb'
import Filter from '../../../components/Filter'
import ProductList from '../../../components/ProductList'
import { routes } from '../../../router/routesList';
import { productTypes } from '../../../redux/productModule'

const Product = () => {

  const category = window.location.pathname.split('/')
  const matches = matchRoutes(routes, window.location.pathname)
  const matched = useMatch(`products/${category[category.length - 1]}`)
  const dispatch = useDispatch()
  const products = useSelector((state) => state.product[category[category.length - 1]])
  const [productSort, setProductSort] = useState()
  useEffect(() => {
    if (products != "") return
    dispatch({ type: productTypes.GET_CATEGORY_PRODUCTS_REQUEST, payload: category[category.length - 1] })
  }, [category])

  useEffect(() => {
    setProductSort(products)
  }, [products])

  const handlePriceSort = (sort) => {
    let sorted = [...products]
    switch (sort) {
      case 'Low':
        sorted.sort((a, b) => {
          return a.product_price * a.product_discount - b.product_price * b.product_discount
        })
        setProductSort(sorted)
        break;
      case 'High':
        sorted.sort((a, b) => {
          return b.product_price * b.product_discount - a.product_price * a.product_discount
        })
        setProductSort(sorted)
        break;
    }
  }
  return (
    <>
      <Row className="my-2 border min-vh-100">
        {matched != null ? (
          <>
            <Col
              sm={2}
              className="min-vh-100 d-none d-md-block border border-secondary m-1 "
            >
              <Filter handlePriceSort={handlePriceSort} />
            </Col>

            <Col className="mt-2">
              <BreadCrumb matches={matches} />
              <div className='d-md-none mb-2'>
                <Filter handlePriceSort={handlePriceSort} />
              </div>
              <ProductList productSort={productSort} />
            </Col>
          </>
        ) : (
          <Col className="mt-2">
            <Outlet />
          </Col>
        )}
      </Row>
    </>
  )
}
export default Product
