import React, { useEffect, useState } from "react";
import { matchRoutes, useNavigate } from 'react-router-dom'
import { routes } from "../../../router/routesList";
import Form from 'react-bootstrap/Form';
import { useSelector, useDispatch } from "react-redux";
import { userTypes } from "../../../redux/userModule";
import BreadCrumb from "../../../components/BreadCrumb";
import { Button } from "react-bootstrap";
import withModal from "../../../HOC/withModal";
import PasswordModal from "../../../components/PasswordModal";

const Profile = () => {
    const PasswordWithModal = withModal(PasswordModal)
    const [isPasswordShow, setIsPasswordShow] = useState(false)
    const matches = matchRoutes(routes, location.pathname)
    const navigate = useNavigate()
    const dispatch = useDispatch()
    const { info } = useSelector((state) => state.user)
    const { _id, user_name, user_role, user_email, user_address } = info

    useEffect(() => {
        if (info && Object.keys(info).length === 0) {
            navigate('/')
        }
    }, [info])

    return (
        <>
            <BreadCrumb matches={matches} />
            <div className="bg-gray">
                <h1 className="mt-2 border text-white d-flex justify-content-center font-title">
                    Profile
                </h1>
            </div >
            <Form >
                <fieldset disabled>
                    <Form.Group className="mb-3  ">
                        <Form.Label
                            className="fw-bold fs-5 mt-1 me-1 font-content">
                            Name :
                        </Form.Label>
                        <Form.Control
                            id="disabledTextInput"
                            placeholder={user_name} />
                    </Form.Group>
                    <Form.Group className="mb-3  ">
                        <Form.Label className="fw-bold fs-5 mt-1 me-1 font-content">Email :</Form.Label>
                        <Form.Control
                            id="disabledTextInput"
                            placeholder={user_email} />
                    </Form.Group>
                    <Form.Group className="mb-3">
                        <Form.Label className="fw-bold fs-5 mt-1 me-1 font-content">Address :</Form.Label>
                        <Form.Control
                            id="disabledTextInput"
                            placeholder={user_address} />
                    </Form.Group>
                </fieldset>
            </Form>
            <div className="d-flex justify-content-end ">
                <PasswordWithModal
                    name="Change Password"
                    userInfo={{ user_id: _id, user_role }}
                    actionType={userTypes.UPDATE_PASSWORD_REQUEST}
                    btnSize={5}
                />
            </div>
        </>
    );
}
export default Profile;