import { useState } from "react";

export const useEditInterface = () => {
    const [isDisplay, setIsDisplay] = useState(false);
    const [value, setValue] = useState(null);

    const openEditInterface = (item) => {
        setIsDisplay(true);
        setValue(item);
    };

    const closeEditInterface = () => {
        setIsDisplay(false);
        setValue(null);
    };

    return { isDisplay, value, setValue, openEditInterface, closeEditInterface };
};