import React, { useState, useEffect, useRef, memo } from 'react';
import { Button, Image } from 'react-bootstrap';

const CartItem = ({
  item, number, userId,
  handleCalculate,
  updateItemQuantity,
  deleteCartItem,
}) => {

  const {
    product_mark,
    product_image,
    product_name,
    product_color,
    product_size,
    product_quantity,
    product_discount,
    product_price,
  } = item

  const quantityRef = useRef(product_quantity)
  const [disabled, setDisabled] = useState(false)

  useEffect(() => {
    handleCalculate(product_price * quantityRef.current * product_discount)
  }, [])

  const UpdateQuantity = () => {
    updateItemQuantity({
      user_id: userId,
      product_mark,
      product_quantity: quantityRef.current
    })
  }


  const handleIncrement = () => {
    if (quantityRef.current >= 1) {
      quantityRef.current++
      handleCalculate(product_price * product_discount)
    }
    UpdateQuantity()
  }

  const handleDecrement = () => {
    if (quantityRef.current <= 1) {
      setDisabled(true);
      return
    }
    quantityRef.current--
    handleCalculate(-product_price * product_discount)
    UpdateQuantity()
    if (quantityRef.current - 1 === 1) {
      setDisabled(false);
    }
  }

  return (
    <tr className="text-center font-content">
      <th>{number + 1}</th>
      <th>
        <Image
          fluid={true}
          responsive="md"
          thumbnail={true}
          width={100}
          height={100}
          className="mx-auto d-block "
          src={product_image}
        />
      </th>
      <th>{product_name}</th>
      <th>{product_color}</th>
      <th>{product_size}</th>
      <th>
        <div className="d-flex">
          <input
            className="me-1 btn-gray"
            type="button"
            disabled={disabled}
            value="-"
            onClick={() => handleDecrement()}
          />
          {quantityRef.current}
          <input
            className="ms-1 btn-gray"
            type="button"
            value="+"
            onClick={() => handleIncrement()}
          />
        </div>
      </th>
      <th>NT{Math.floor(product_price * quantityRef.current * product_discount)}$</th>
      <th >
        <Button
          className='mt-2 btn-beige border border-1 border-black font-content'
          onClick={() =>
            deleteCartItem({
              user_id: userId,
              product_mark
            }, product_price * quantityRef.current * product_discount)
          }>
          Delete
        </Button>
      </th>
    </tr>
  )
}
function areEqual(prevProps, nextProps) {
  const compareItem = prevProps.item.product_mark === nextProps.item.product_mark;
  if (compareItem) {
    return prevProps.item.product_quantity === nextProps.item.product_quantity;
  }
  return prevProps === nextProps;
}
export default memo(CartItem, areEqual)
